    "reasoning": "<lý do phân tích 2-3 câu bằng tiếng Việt>"
  },
  "summary": "<tóm tắt thị trường 2-3 câu bằng tiếng Việt>",
  "keyLevels": {
    "support": ["<giá1>", "<giá2>"],
    "resistance": ["<giá1>", "<giá2>"]
  },
  "indicators": [
    { "name": "Volume", "value": "<giá trị>", "interpretation": "<nhận xét ngắn bằng tiếng Việt>" },
    { "name": "Spread", "value": "<giá trị>", "interpretation": "<nhận xét ngắn bằng tiếng Việt>" },
